// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb.benchmark;

import static org.junit.jupiter.api.Assertions.assertTrue;

import java.lang.reflect.Field;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

import org.eclipse.rdf4j.query.algebra.evaluation.sketch.SketchBasedJoinEstimator;
import org.junit.jupiter.api.Test;

class AASQueriesBenchmarkTest {

	@Test
	void setupQuiescesSketchEstimatorRefreshThreadBeforeMeasurement() throws Exception {
		AASQueriesBenchmark benchmark = new AASQueriesBenchmark();
		configureBenchmark(benchmark);
		Set<Long> refreshThreadsBeforeSetup = liveRefreshThreadIds();

		try {
			benchmark.setup();

			List<Thread> newRefreshThreads = liveRefreshThreads().stream()
					.filter(thread -> !refreshThreadsBeforeSetup.contains(thread.threadId()))
					.toList();
			assertTrue(newRefreshThreads.isEmpty(),
					"benchmark setup must not leave sketch refresh threads alive: " + describe(newRefreshThreads));
		} finally {
			benchmark.tearDown();
		}
	}

	private static void configureBenchmark(AASQueriesBenchmark benchmark) throws ReflectiveOperationException {
		setField(benchmark, "productionLineCount", 1);
		setField(benchmark, "driveUnitCount", 1);
		setField(benchmark, "sensorCount", 1);
		setField(benchmark, "store", "lmdb");
		setField(benchmark, "useCascades", "true");
		setField(benchmark, "query", "query2ThresholdCount");
	}

	private static void setField(AASQueriesBenchmark benchmark, String name, Object value)
			throws ReflectiveOperationException {
		Field field = AASQueriesBenchmark.class.getDeclaredField(name);
		field.setAccessible(true);
		field.set(benchmark, value);
	}

	private static Set<Long> liveRefreshThreadIds() {
		return liveRefreshThreads().stream()
				.map(Thread::threadId)
				.collect(Collectors.toSet());
	}

	private static List<Thread> liveRefreshThreads() {
		return Thread.getAllStackTraces()
				.keySet()
				.stream()
				.filter(Thread::isAlive)
				.filter(thread -> SketchBasedJoinEstimator.REFRESH_THREAD_NAME.equals(thread.getName()))
				.toList();
	}

	private static String describe(List<Thread> threads) {
		return threads.stream()
				.map(thread -> thread.getName() + "#" + thread.threadId() + ":" + thread.getState())
				.collect(Collectors.joining(", "));
	}
}
